package commands

import (
	"errors"

	"github.com/google/uuid"
)

type ProgressStatus string

const (
	ProgressStatusInProgress ProgressStatus = "IN_PROGRESS"
	ProgressStatusCompleted  ProgressStatus = "COMPLETED"
)

var ErrInvalidProgressStatus = errors.New("invalid progress status")

type EnrollmentProgress struct {
	userId  uuid.UUID
	topicId uuid.UUID
	status  ProgressStatus
}

func NewEnrollmentProgress(userId, topicId uuid.UUID) EnrollmentProgress {
	return EnrollmentProgress{
		userId:  userId,
		topicId: topicId,
	}
}

func (p *EnrollmentProgress) Start() {
	p.status = ProgressStatusInProgress
}

func (p *EnrollmentProgress) Finish() {
	p.status = ProgressStatusCompleted
}

func (p *EnrollmentProgress) UserId() uuid.UUID {
	return p.userId
}

func (p *EnrollmentProgress) TopicId() uuid.UUID {
	return p.topicId
}

func (p *EnrollmentProgress) Status() ProgressStatus {
	return p.status
}

package commands

import (
	"encoding/json"
	"errors"
	"log"
	"net/http"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/lib/response"
	"github.com/jackc/pgx/v5"
)

const (
	errorCodeEnrollmentForbidden = "ENROLLMENT_FORBIDDEN"
	errorCodeCourseNotFound      = "COURSE_NOT_FOUND"
	errorCodeTopicNotFound       = "TOPIC_NOT_FOUND"
)

type UpdateEnrollmentHandler struct {
	usecase UpdateEnrollmentUsecaseInterface
}

func NewUpdateEnrollmentHandler(usecase UpdateEnrollmentUsecaseInterface) *UpdateEnrollmentHandler {
	return &UpdateEnrollmentHandler{usecase: usecase}
}

type patchEnrollmentRequestBody struct {
	TopicId string `json:"topicId"`
	Status  string `json:"status"`
}

type patchEnrollmentResponse struct {
	TopicId string `json:"topicId"`
	Status  string `json:"status"`
}

func (h *UpdateEnrollmentHandler) PatchEnrollmentHandler(w http.ResponseWriter, r *http.Request) {
	w.Header().Set("Content-Type", "application/json")

	userIdStr := r.PathValue("userID")
	if userIdStr == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "userID must be required")
		return
	}
	userId, err := uuid.Parse(userIdStr)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "userID must be UUID format")
		return
	}

	courseIdStr := r.PathValue("courseId")
	if courseIdStr == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "courseId must be required")
		return
	}
	courseId, err := uuid.Parse(courseIdStr)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "courseId must be UUID format")
		return
	}

	var body patchEnrollmentRequestBody
	defer r.Body.Close()
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "body parameter is invalid json format")
		return
	}

	if body.TopicId == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "topicId must be required")
		return
	}
	topicId, err := uuid.Parse(body.TopicId)
	if err != nil {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "topicId must be UUID format")
		return
	}

	if body.Status == "" {
		response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "status must be required")
		return
	}

	result, err := h.usecase.execute(r.Context(), UpdateEnrollmentParams{
		userId:   userId,
		courseId: courseId,
		topicId:  topicId,
		status:   body.Status,
	})
	if err != nil {
		switch {
		case errors.Is(err, ErrInvalidProgressStatus):
			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "status must be IN_PROGRESS or COMPLETED")
		case errors.Is(err, pgx.ErrNoRows):
			response.WriteErrorResponse(w, http.StatusNotFound, errorCodeCourseNotFound, "course not found")
		case errors.Is(err, ErrEnrollmentNotAllowed):
			response.WriteErrorResponse(w, http.StatusForbidden, errorCodeEnrollmentForbidden, "this course is not enrollable")
		case errors.Is(err, ErrTopicNotFoundInCourse):
			response.WriteErrorResponse(w, http.StatusNotFound, errorCodeTopicNotFound, "topic not found in course")
		default:
			log.Printf("PatchEnrollmentHandler error: %v", err)
			response.WriteInternalServerErrorResponse(w)
		}
		return
	}

	w.WriteHeader(http.StatusOK)
	_ = json.NewEncoder(w).Encode(patchEnrollmentResponse{
		TopicId: result.TopicId,
		Status:  result.Status,
	})
}

package commands

import (
	"context"
	"encoding/json"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcCourseRepository struct {
	sqrc db.Querier
}

func NewSqrcCourseRepository(q db.Querier) *SqrcCourseRepository {
	return &SqrcCourseRepository{sqrc: q}
}

func (repository *SqrcCourseRepository) getCourseByCourseId(ctx context.Context, courseId uuid.UUID) (Course, error) {
	var courseIdUuid pgtype.UUID

	if err := courseIdUuid.Scan(courseId.String()); err != nil {
		return Course{}, err
	}

	courseRaw, err := repository.sqrc.GetCourseById(ctx, courseIdUuid)
	if err != nil {
		return Course{}, err
	}

	return toCourse(courseRaw), nil
}

func toCourse(raw db.GetCourseByIdRow) Course {
	var tags []string
	json.Unmarshal(raw.Tags, &tags)

	type topicRaw struct {
		CourseSectionTopicId string `json:"course_section_topic_id"`
		Title                string `json:"title"`
		Description          string `json:"description"`
		Prerequisites        string `json:"prerequisites"`
		Knowledge            string `json:"knowledge"`
		Flow                 string `json:"flow"`
		Quiz                 string `json:"quiz"`
		CompletionCriteria   string `json:"completion_criteria"`
	}
	type sectionRaw struct {
		CourseSectionId string     `json:"course_section_id"`
		Title           string     `json:"title"`
		Description     string     `json:"description"`
		Topics          []topicRaw `json:"topics"`
	}

	var sectionsRaw []sectionRaw
	json.Unmarshal(raw.Sections, &sectionsRaw)

	sections := make([]Section, len(sectionsRaw))
	for i, s := range sectionsRaw {
		topics := make([]Topic, len(s.Topics))
		for j, t := range s.Topics {
			topics[j] = Topic{
				topicId:            t.CourseSectionTopicId,
				title:              t.Title,
				description:        t.Description,
				prerequisites:      t.Prerequisites,
				knowledge:          t.Knowledge,
				flow:               t.Flow,
				quiz:               t.Quiz,
				completionCriteria: t.CompletionCriteria,
				number:             j,
			}
		}
		sections[i] = Section{
			sectionId:   s.CourseSectionId,
			title:       s.Title,
			description: s.Description,
			number:      i,
			topics:      topics,
		}
	}

	var publishedAt *string
	if raw.PublishedAt.Valid {
		t := raw.PublishedAt.Time.Format(time.RFC3339)
		publishedAt = &t
	}

	return Course{
		courseId:      raw.CourseID.String(),
		title:         raw.Title,
		description:   raw.Description,
		slug:          raw.Slug,
		tags:          tags,
		publishStatus: raw.PublishStatus,
		category: Category{
			categoryId: raw.CategoryID.String(),
			name:       raw.CategoryName,
		},
		publishedAt: publishedAt,
		author: Author{
			authorId: raw.AuthorID.String(),
			name:     raw.AuthorName,
		},
		visibility: raw.Visibility,
		sections:   sections,
	}
}

