package commands

import (
	"testing"

	"github.com/google/uuid"
)

func TestEnrollmentProgress_Start(t *testing.T) {
	t.Run("Startを呼ぶとstatusがIN_PROGRESSになる", func(t *testing.T) {
		p := NewEnrollmentProgress(uuid.New(), uuid.New())
		p.Start()
		if p.Status() != ProgressStatusInProgress {
			t.Errorf("statusがIN_PROGRESSであること: got %q", p.Status())
		}
	})
}

func TestEnrollmentProgress_Finish(t *testing.T) {
	t.Run("Finishを呼ぶとstatusがCOMPLETEDになる", func(t *testing.T) {
		p := NewEnrollmentProgress(uuid.New(), uuid.New())
		p.Finish()
		if p.Status() != ProgressStatusCompleted {
			t.Errorf("statusがCOMPLETEDであること: got %q", p.Status())
		}
	})
}

func TestEnrollmentProgress_Accessors(t *testing.T) {
	t.Run("UserIdとTopicIdはコンストラクタで指定した値を返す", func(t *testing.T) {
		userId := uuid.New()
		topicId := uuid.New()
		p := NewEnrollmentProgress(userId, topicId)
		if p.UserId() != userId {
			t.Errorf("UserIdが一致すること: got %v, want %v", p.UserId(), userId)
		}
		if p.TopicId() != topicId {
			t.Errorf("TopicIdが一致すること: got %v, want %v", p.TopicId(), topicId)
		}
	})
}

