1	package queries
2	
3	import (
4		"context"
5		"encoding/json"
6		"errors"
7		"log"
8		"net/http"
9	
10		"github.com/harusame0616/ijuku/apps/api/internal/db"
11		"github.com/harusame0616/ijuku/apps/api/lib/response"
12		"github.com/jackc/pgx/v5"
13		"github.com/jackc/pgx/v5/pgtype"
14	)
15	
16	const (
17		progressStatusNotStarted = "NOT_STARTED"
18		progressStatusInProgress = "IN_PROGRESS"
19		progressStatusCompleted  = "COMPLETED"
20		coursePublishStatusPub   = "published"
21	
22		errorCodeCourseNotFound     = "COURSE_NOT_FOUND"
23		errorCodeEnrollmentForbidden = "ENROLLMENT_FORBIDDEN"
24	)
25	
26	type GetEnrollmentQuery interface {
27		GetCourseAuthorityById(ctx context.Context, courseid pgtype.UUID) (db.GetCourseAuthorityByIdRow, error)
28		GetCourseStructureWithProgress(ctx context.Context, arg db.GetCourseStructureWithProgressParams) (db.GetCourseStructureWithProgressRow, error)
29	}
30	
31	type GetEnrollmentHandler struct {
32		query GetEnrollmentQuery
33	}
34	
35	func NewGetEnrollmentHandler(q GetEnrollmentQuery) *GetEnrollmentHandler {
36		return &GetEnrollmentHandler{query: q}
37	}
38	
39	// SQL の jsonb 配列をそのまま受ける中間構造体。
40	// section_agg / jsonb_build_object のキーと一致させる。
41	type rawTopic struct {
42		TopicId string `json:"topicId"`
43		Title   string `json:"title"`
44		Status  string `json:"status"`
45		Index   int    `json:"index"`
46	}
47	
48	type rawSection struct {
49		SectionId string     `json:"sectionId"`
50		Title     string     `json:"title"`
51		Index     int        `json:"index"`
52		Topics    []rawTopic `json:"topics"`
53	}
54	
55	type getEnrollmentTopicResponse struct {
56		TopicId string `json:"topicId"`
57		Title   string `json:"title"`
58		Status  string `json:"status"`
59	}
60	
61	type getEnrollmentSectionResponse struct {
62		SectionId string                       `json:"sectionId"`
63		Title     string                       `json:"title"`
64		Topics    []getEnrollmentTopicResponse `json:"topics"`
65	}
66	
67	type getEnrollmentNextTopicResponse struct {
68		SectionId string `json:"sectionId"`
69		TopicId   string `json:"topicId"`
70	}
71	
72	type GetEnrollmentResponse struct {
73		CourseId  string                          `json:"courseId"`
74		Title     string                          `json:"title"`
75		Sections  []getEnrollmentSectionResponse  `json:"sections"`
76		NextTopic *getEnrollmentNextTopicResponse `json:"nextTopic"`
77	}
78	
79	func (h *GetEnrollmentHandler) GetEnrollmentHandler(w http.ResponseWriter, r *http.Request) {
80		w.Header().Set("Content-Type", "application/json")
81	
82		var userID pgtype.UUID
83		if err := userID.Scan(r.PathValue("userID")); err != nil {
84			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "userID must be a valid UUID")
85			return
86		}
87	
88		var courseID pgtype.UUID
89		if err := courseID.Scan(r.PathValue("courseId")); err != nil {
90			response.WriteErrorResponse(w, http.StatusBadRequest, response.InputValidationError, "courseId must be a valid UUID")
91			return
92		}
93	
94		authority, err := h.query.GetCourseAuthorityById(r.Context(), courseID)
95		if err != nil {
96			if errors.Is(err, pgx.ErrNoRows) {
97				response.WriteErrorResponse(w, http.StatusNotFound, errorCodeCourseNotFound, "course not found")
98				return
99			}
100			log.Printf("GetCourseAuthorityById error: %v", err)
101			response.WriteInternalServerErrorResponse(w)
102			return
103		}
104	
105		if authority.PublishStatus != coursePublishStatusPub && authority.AuthorID.Bytes != userID.Bytes {
106			response.WriteErrorResponse(w, http.StatusForbidden, errorCodeEnrollmentForbidden, "this course is not enrollable")
107			return
108		}
109	
110		row, err := h.query.GetCourseStructureWithProgress(r.Context(), db.GetCourseStructureWithProgressParams{
111			Courseid: courseID,
112			Userid:   userID,
113		})
114		if err != nil {
115			log.Printf("GetCourseStructureWithProgress error: %v", err)
116			response.WriteInternalServerErrorResponse(w)
117			return
118		}
119	
120		rawSections, err := unmarshalSections(row.Sections)
121		if err != nil {
122			log.Printf("unmarshal sections error: %v", err)
123			response.WriteInternalServerErrorResponse(w)
124			return
125		}
126	
127		_ = json.NewEncoder(w).Encode(GetEnrollmentResponse{
128			CourseId:  courseID.String(),
129			Title:     row.Title,
130			Sections:  buildSections(rawSections),
131			NextTopic: decideNextTopic(rawSections),
132		})
133	}
134	
135	func unmarshalSections(raw []byte) ([]rawSection, error) {
136		if len(raw) == 0 {
137			return nil, nil
138		}
139		var sections []rawSection
140		if err := json.Unmarshal(raw, &sections); err != nil {
141			return nil, err
142		}
143		return sections, nil
144	}
145	
146	func buildSections(rawSecs []rawSection) []getEnrollmentSectionResponse {
147		sections := make([]getEnrollmentSectionResponse, 0, len(rawSecs))
148		for _, rs := range rawSecs {
149			topics := make([]getEnrollmentTopicResponse, 0, len(rs.Topics))
150			for _, rt := range rs.Topics {
151				topics = append(topics, getEnrollmentTopicResponse{
152					TopicId: rt.TopicId,
153					Title:   rt.Title,
154					Status:  rt.Status,
155				})
156			}
157			sections = append(sections, getEnrollmentSectionResponse{
158				SectionId: rs.SectionId,
159				Title:     rs.Title,
160				Topics:    topics,
161			})
162		}
163		return sections
164	}
165	
166	// decideNextTopic は section/topic の index ASC 順に並んだ rawSection から、
167	// 次に取るべき topic を course.entity.go の findTopicToStart/nextTopic 踏襲で決定する。
168	//   - 全 NOT_STARTED                                  -> 先頭トピック
169	//   - (sec_idx, top_idx) 最大の非 NOT_STARTED が IN_PROGRESS -> その topic
170	//   - 同上が COMPLETED かつ次の topic がある           -> 次の topic
171	//   - 同上が COMPLETED かつ最終位置 (= 全完了)         -> nil
172	func decideNextTopic(rawSecs []rawSection) *getEnrollmentNextTopicResponse {
173		if len(rawSecs) == 0 {
174			return nil
175		}
176	
177		lastSecIdx, lastTopIdx := -1, -1
178		var lastStatus string
179		for si, sec := range rawSecs {
180			for ti, top := range sec.Topics {
181				if top.Status == progressStatusNotStarted {
182					continue
183				}
184				lastSecIdx, lastTopIdx = si, ti
185				lastStatus = top.Status
186			}
187		}
188	
189		if lastSecIdx == -1 {
190			return firstTopic(rawSecs)
191		}
192	
193		switch lastStatus {
194		case progressStatusInProgress:
195			return topicAt(rawSecs, lastSecIdx, lastTopIdx)
196		case progressStatusCompleted:
197			if nextSec, nextTop, ok := nextPosition(rawSecs, lastSecIdx, lastTopIdx); ok {
198				return topicAt(rawSecs, nextSec, nextTop)
199			}
200			return nil
201		default:
202			return firstTopic(rawSecs)
203		}
204	}
205	
206	// nextPosition は course.entity.go の nextTopic を踏襲。
207	// (secIdx, topIdx) が最終位置なら ok=false を返す。
208	func nextPosition(rawSecs []rawSection, secIdx, topIdx int) (int, int, bool) {
209		if secIdx < 0 || secIdx >= len(rawSecs) {
210			return 0, 0, false
211		}
212		sec := rawSecs[secIdx]
213		if topIdx < 0 || topIdx >= len(sec.Topics) {
214			return 0, 0, false
215		}
216		if topIdx == len(sec.Topics)-1 {
217			if secIdx == len(rawSecs)-1 {
218				return 0, 0, false
219			}
220			return secIdx + 1, 0, true
221		}
222		return secIdx, topIdx + 1, true
223	}
224	
225	func firstTopic(rawSecs []rawSection) *getEnrollmentNextTopicResponse {
226		if len(rawSecs) == 0 || len(rawSecs[0].Topics) == 0 {
227			return nil
228		}
229		return &getEnrollmentNextTopicResponse{
230			SectionId: rawSecs[0].SectionId,
231			TopicId:   rawSecs[0].Topics[0].TopicId,
232		}
233	}
234	
235	func topicAt(rawSecs []rawSection, secIdx, topIdx int) *getEnrollmentNextTopicResponse {
236		if secIdx < 0 || secIdx >= len(rawSecs) {
237			return nil
238		}
239		sec := rawSecs[secIdx]
240		if topIdx < 0 || topIdx >= len(sec.Topics) {
241			return nil
242		}
243		return &getEnrollmentNextTopicResponse{
244			SectionId: sec.SectionId,
245			TopicId:   sec.Topics[topIdx].TopicId,
246		}
247	}
248

