	var userIdUuid, courseIdUuid pgtype.UUID
	if err := userIdUuid.Scan(userId.String()); err != nil {
		return Enrollment{}, err
	}
	if err := courseIdUuid.Scan(courseId.String()); err != nil {
		return Enrollment{}, err
