	_, _ = pool.Exec(ctx, `DELETE FROM enrollments WHERE user_id = ANY($1)`, users)
	_, _ = pool.Exec(ctx, `DELETE FROM course_section_topics WHERE course_id = ANY($1)`, courses)
	_, _ = pool.Exec(ctx, `DELETE FROM course_sections WHERE course_id = ANY($1)`, courses)
	_, _ = pool.Exec(ctx, `DELETE FROM courses WHERE course_id = ANY($1)`, courses)
	_, _ = pool.Exec(ctx, `DELETE FROM users WHERE user_id = ANY($1)`, users)
	_, _ = pool.Exec(ctx, `DELETE FROM authors WHERE author_id = $1`, mediumTestAuthorID)
	_, _ = pool.Exec(ctx, `DELETE FROM categories WHERE category_id = $1`, mediumTestCategoryID)
}

func cleanupMediumProgresses(ctx context.Context, pool *pgxpool.Pool) {
	users := []string{mediumTestUserID, mediumTestOtherUser}
	_, _ = pool.Exec(ctx, `DELETE FROM topic_progresses WHERE enrollment_id IN (SELECT enrollment_id FROM enrollments WHERE user_id = ANY($1))`, users)
	_, _ = pool.Exec(ctx, `DELETE FROM enrollments WHERE user_id = ANY($1)`, users)
}

// upsertEnrollment は (userID, courseID) の enrollment を取得 or 新規作成して enrollment_id を返す。
func upsertEnrollment(ctx context.Context, pool *pgxpool.Pool, userID, courseID string, enrolledAt time.Time) (string, error) {
	var enrollmentID string
	err := pool.QueryRow(ctx,
		`SELECT enrollment_id FROM enrollments WHERE user_id = $1 AND course_id = $2`,
		userID, courseID,
	).Scan(&enrollmentID)
	if err == nil {
		return enrollmentID, nil
	}
	enrollmentID = uuid.NewString()
	_, err = pool.Exec(ctx,
		`INSERT INTO enrollments (enrollment_id, user_id, course_id, enrolled_at) VALUES ($1, $2, $3, $4)`,
		enrollmentID, userID, courseID, enrolledAt,
	)
	return enrollmentID, err
}

// insertProgress は topic に対する IN_PROGRESS 進捗を記録する。
// 既に enrollment が無ければ自動作成。
func insertProgress(ctx context.Context, pool *pgxpool.Pool, userID, topicID string, updatedAt time.Time) error {
	courseID, err := courseIDOfTopic(ctx, pool, topicID)
	if err != nil {
		return err
	}
	enrollmentID, err := upsertEnrollment(ctx, pool, userID, courseID, updatedAt)
	if err != nil {
		return err
	}
	_, err = pool.Exec(ctx,
		`INSERT INTO topic_progresses (enrollment_id, course_section_topic_id, status, _updated_at) VALUES ($1, $2, 'IN_PROGRESS', $3)
		 ON CONFLICT (enrollment_id, course_section_topic_id) DO UPDATE SET status = EXCLUDED.status, _updated_at = EXCLUDED._updated_at`,
		enrollmentID, topicID, updatedAt,
	)
	if err != nil {
		return err
	}
	// enrollments._updated_at も並び順テストに使うので追従させる
	_, err = pool.Exec(ctx, `UPDATE enrollments SET _updated_at = $1 WHERE enrollment_id = $2`, updatedAt, enrollmentID)
	return err
}

func courseIDOfTopic(ctx context.Context, pool *pgxpool.Pool, topicID string) (string, error) {
	var courseID string
	err := pool.QueryRow(ctx,
		`SELECT course_id FROM course_section_topics WHERE course_section_topic_id = $1`,
		topicID,
	).Scan(&courseID)
	return courseID, err
}

