		req.SetPathValue("courseId", courseID)
		return req
	}

	t.Run("受講中コースの未進捗トピックをIN_PROGRESSで開始できる", func(t *testing.T) {
		t.Cleanup(func() { cleanupUpdateProgresses(ctx, pool) })
